import{_ as t,o as i,c as n,ag as s}from"./chunks/framework.BiKM_w0q.js";const p=JSON.parse(`{"title":"Menus — Vue d'ensemble","description":"","frontmatter":{},"headers":[],"relativePath":"menus/index.md","filePath":"menus/index.md"}`),l={name:"menus/index.md"};function a(o,e,r,u,c,d){return i(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="menus-—-vue-d-ensemble" tabindex="-1">Menus — Vue d&#39;ensemble <a class="header-anchor" href="#menus-—-vue-d-ensemble" aria-label="Permalink to &quot;Menus — Vue d&#39;ensemble&quot;">​</a></h1><p>ox_lib propose deux types de menus avec un style GTA/ScaleformUI natif :</p><h2 id="list-menu-lib-registermenu" tabindex="-1">List Menu (<code>lib.registerMenu</code>) <a class="header-anchor" href="#list-menu-lib-registermenu" aria-label="Permalink to &quot;List Menu (`lib.registerMenu`)&quot;">​</a></h2><p>Menu de type liste avec navigation clavier/souris. Supporte :</p><ul><li>Boutons, séparateurs, checkboxes</li><li>Scroll de valeurs (gauche/droite)</li><li>Sliders de progression</li><li>Palettes de couleurs</li><li>Champs texte</li><li>Bannières personnalisables</li></ul><p>→ <a href="/Fantastic-docs/menus/list-menu">Documentation complète</a></p><h2 id="context-menu-lib-registercontext" tabindex="-1">Context Menu (<code>lib.registerContext</code>) <a class="header-anchor" href="#context-menu-lib-registercontext" aria-label="Permalink to &quot;Context Menu (`lib.registerContext`)&quot;">​</a></h2><p>Menu contextuel avec items cliquables. Supporte :</p><ul><li>Boutons avec icônes, métadonnées, flèches</li><li>Sous-menus imbriqués</li><li>Barres de progression</li><li>Events client/serveur directs</li><li>Bannières personnalisables</li></ul><p>→ <a href="/Fantastic-docs/menus/context-menu">Documentation complète</a></p><h2 id="style-visuel-commun" tabindex="-1">Style visuel commun <a class="header-anchor" href="#style-visuel-commun" aria-label="Permalink to &quot;Style visuel commun&quot;">​</a></h2><p>Les deux types de menus partagent le même style GTA natif :</p><ul><li>Fond noir <code>rgba(0, 0, 0, 0.82)</code></li><li>Hover blanc <code>rgba(255, 255, 255, 1)</code> + texte noir</li><li>Border-radius <code>0</code> partout</li><li>Header personnalisable (couleur ou image bannière)</li></ul><p>→ <a href="/Fantastic-docs/menus/style">Détails du style</a></p>',14)])])}const b=t(l,[["render",a]]);export{p as __pageData,b as default};
